dashboard.definition:
{
  "title": "Source - Webex TA",
  "description": "Cisco Webex Technical Add-on — meeting quality metrics and room utilization tracking",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Webex TA Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:*\" by _time span=1h"
      }
    },
    "ds_unique_rooms": {
      "type": "ds.search",
      "name": "Unique Rooms",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingusagehistory\" confName=* | stats dc(confName) as count"
      }
    },
    "ds_quality_issues": {
      "type": "ds.search",
      "name": "Total Meetings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingusagehistory\" | stats count"
      }
    },
    "ds_meeting_hours": {
      "type": "ds.search",
      "name": "Meeting Hours",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingusagehistory\" duration=* | stats sum(duration) as total_min | eval count=round(total_min/60,0).\" hrs\""
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Events Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:*\" | timechart span=1h count"
      }
    },
    "ds_by_sourcetype": {
      "type": "ds.search",
      "name": "Events by Sourcetype",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:*\" by sourcetype"
      }
    },
    "ds_top_rooms": {
      "type": "ds.search",
      "name": "Top Meeting Rooms by Usage",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:meetingusagehistory\" hostEmail=* | stats count by hostEmail | sort -count | head 15 | rename hostEmail as \"Host\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cisco:webex:meetings:history:*\" | table _time confName hostEmail duration peakAttendee | sort -_time | head 30 | rename confName as \"Meeting\" hostEmail as \"Host\" duration as \"Duration (min)\" peakAttendee as \"Attendees\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Webex TA\n\n**Sourcetypes:** `FAKE:cisco:webex:meetings:history:meetingusagehistory`, `FAKE:cisco:webex:meetings:history:meetingattendeehistory` | **Coverage:** Meeting history and participant data | **Format:** JSON\n\n**Why monitor?** Track meeting quality metrics to identify rooms with recurring audio/video issues, and optimize conference room utilization across all locations.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Events",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_rooms": {
      "type": "splunk.singlevalue",
      "title": "Unique Rooms",
      "dataSources": { "primary": "ds_unique_rooms" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_quality_issues": {
      "type": "splunk.singlevalue",
      "title": "Total Meetings",
      "dataSources": { "primary": "ds_quality_issues" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_meeting_hours": {
      "type": "splunk.singlevalue",
      "title": "Meeting Hours",
      "dataSources": { "primary": "ds_meeting_hours" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Events Over Time",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "legendDisplay": "off",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#00D2FF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_by_sourcetype": {
      "type": "splunk.pie",
      "title": "Events by Sourcetype",
      "dataSources": { "primary": "ds_by_sourcetype" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#00D2FF", "#7B56DB"]
      }
    },
    "viz_top_rooms": {
      "type": "splunk.bar",
      "title": "Top Meeting Rooms by Usage",
      "dataSources": { "primary": "ds_top_rooms" },
      "options": {
        "seriesColors": ["#53A051"],
        "legendDisplay": "off",
        "xAxisTitleText": "Meetings",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Events",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Events",
      "dataSources": { "primary": "ds_sample_events" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_rooms", "type": "block", "position": { "x": 300, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_quality_issues", "type": "block", "position": { "x": 600, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_meeting_hours", "type": "block", "position": { "x": 900, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 750, "h": 350 } },
      { "item": "viz_by_sourcetype", "type": "block", "position": { "x": 750, "y": 270, "w": 450, "h": 350 } },
      { "item": "viz_top_rooms", "type": "block", "position": { "x": 0, "y": 620, "w": 1200, "h": 300 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 920, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 970, "w": 1200, "h": 400 } }
    ]
  }
}
